# and what they indicate.

for i, s in enumerate(train_samples):
    inp = np.array(s['input'])
    out = np.array(s['output'])
    # Find the disappearing color
    colors_in = set(inp.flatten()) - {0}
    colors_out = set(out.flatten()) - {0}
    marker = (colors_in - colors_out).pop()

    marker_positions = np.argwhere(inp == marker)
    print(f"\n=== Example {i} (marker={int(marker)}) ===")
    for r, c in marker_positions:
        print(f"  Marker at ({r},{c}): becomes {int(out[r,c])} in output")
        # What's around the marker?
        neighbors = []
        for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
            nr, nc = r+dr, c+dc
            if 0 <= nr < inp.shape[0] and 0 <= nc < inp.shape[1]:
                neighbors.append(((int(nr),int(nc)), int(inp[nr,nc]), int(out[nr,nc])))
        print(f"    Neighbors (in): {neighbors}")

