import numpy as np

def analyze_markers(grid):
    """Find marker colors and their replacements"""
    g = np.array(grid)
    H, W = g.shape
    colors = set(g.flatten()) - {0}

    results = {}
    for mc in [2, 4]:
        if mc not in colors:
            continue
        positions = list(map(tuple, np.argwhere(g == mc).tolist()))
        replacements = {}
        for r, c in positions:
            # Find adjacent non-zero, non-marker colors
            adj_colors = []
            for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
                nr, nc = r+dr, c+dc
                if 0 <= nr < H and 0 <= nc < W and g[nr,nc] != 0 and g[nr,nc] != 2 and g[nr,nc] != 4:
                    adj_colors.append(int(g[nr,nc]))
            if adj_colors:
                # Most common adjacent color
                from collections import Counter
                replacements[(r,c)] = Counter(adj_colors).most_common(1)[0][0]
        results[mc] = {'positions': positions, 'replacements': replacements}
    return results

for i, s in enumerate(train_samples):
    print(f"\n=== Example {i} ===")
    info = analyze_markers(s['input'])
    for mc, data in info.items():
        print(f"  Marker {mc}:")
        for pos, repl in data['replacements'].items():
            print(f"    {pos} -> {repl}")

