def solve(grid):
    import numpy as np
    from collections import Counter, defaultdict

    g = np.array(grid, dtype=int)
    H, W = g.shape
    out = g.copy()
    orig = g.copy()

    # Find marker colors
    colors = set(g.flatten().tolist()) - {0}

    # Determine which colors are markers (2 and/or 4)
    # Marker 2: corner markers, Marker 4: direction markers
    marker_colors = set()
    if 2 in colors:
        marker_colors.add(2)
    if 4 in colors:
        marker_colors.add(4)

    if not marker_colors:
        return grid  # No transformation needed

    # For each marker cell, determine its line color
    marker_info = {}  # (r,c) -> {'type': 2 or 4, 'color': line_color}
    for r in range(H):
        for c in range(W):
            if g[r,c] in marker_colors:
                adj = []
                for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
                    nr, nc = r+dr, c+dc
                    if 0 <= nr < H and 0 <= nc < W and g[nr,nc] not in marker_colors and g[nr,nc] != 0:
                        adj.append(int(g[nr,nc]))
                color = Counter(adj).most_common(1)[0][0] if adj else 0
                marker_info[(r,c)] = {'type': int(g[r,c]), 'color': color}

    # Replace all markers with their line colors
    for (r,c), info in marker_info.items():
        out[r,c] = info['color']

    # Handle arm flipping for marker 4
    for (r,c), info in marker_info.items():
        if info['type'] != 4:
            continue

        line_color = info['color']
        # Find the adjacent corner (the cell the marker is adjacent to with the line color)
        corner = None
        for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
            nr, nc = r+dr, c+dc
            if 0 <= nr < H and 0 <= nc < W:
                if out[nr,nc] == line_color:
                    corner = (nr, nc)
                    flip_dir = (r - nr, c - nc)  # direction from corner to marker
                    break

        if corner is None:
            continue

        cr, cc = corner
        opp_dir = (-flip_dir[0], -flip_dir[1])  # opposite of flip direction

        # Remove cells in opposite direction from corner (the wrong-side arm)
        nr, nc = cr + opp_dir[0], cc + opp_dir[1]
        while 0 <= nr < H and 0 <= nc < W:
            if out[nr, nc] == line_color:
                out[nr, nc] = 0
            elif out[nr, nc] == 0:
                break  # stop at gap
            else:
                break  # stop at different color
            nr += opp_dir[0]
            nc += opp_dir[1]

        # Extend arm from marker in flip direction to boundary (fill 0s)
        nr, nc = r + flip_dir[0], c + flip_dir[1]
        while 0 <= nr < H and 0 <= nc < W:
            if out[nr, nc] == 0:
                out[nr, nc] = line_color
            else:
                break  # stop at non-zero cell
            nr += flip_dir[0]
            nc += flip_dir[1]

    # Now fill gaps between markers of the same color on the same row/column
    # Group markers by color
    markers_by_color = defaultdict(list)
    for (r,c), info in marker_info.items():
        markers_by_color[info['color']].append((r, c))

    for color, positions in markers_by_color.items():
        # Find pairs on the same row
        by_row = defaultdict(list)
        by_col = defaultdict(list)
        for r, c in positions:
            by_row[r].append(c)
            by_col[c].append(r)

        for row, cols in by_row.items():
            cols.sort()
            for i in range(len(cols) - 1):
                c1, c2 = cols[i], cols[i+1]
                for c in range(c1, c2+1):
                    if out[row, c] == 0 or out[row, c] == color:
                        out[row, c] = color

        for col, rows in by_col.items():
            rows.sort()
            for i in range(len(rows) - 1):
                r1, r2 = rows[i], rows[i+1]
                for r in range(r1, r2+1):
                    if out[r, col] == 0 or out[r, col] == color:
                        out[r, col] = color

    # Extend endpoint markers to boundary
    # For each marker position, check if it has a non-marker same-color neighbor
    # in only one direction on each axis. If so, extend in the other direction.
    for color, positions in markers_by_color.items():
        for r, c in positions:
            # Check horizontal: does the arm extend left, right, both, or neither?
            has_left = c > 0 and out[r, c-1] == color
            has_right = c < W-1 and out[r, c+1] == color
            has_up = r > 0 and out[r-1, c] == color
            has_down = r < H-1 and out[r+1, c] == color

            # If this marker has same-color only in one horizontal direction,
            # it might need to extend in the other direction
            # But actually, we should extend in the direction of the arm
            # For now, I'll skip this - the between-markers fill should handle most cases

    # Fill 1-cell 0-gaps for all non-zero colors
    changed = True
    while changed:
        changed = False
        new_out = out.copy()
        for r in range(H):
            for c in range(W):
                if new_out[r, c] == 0:
                    # Check left-right
                    if c > 0 and c < W-1 and new_out[r, c-1] != 0 and new_out[r, c-1] == new_out[r, c+1]:
                        new_out[r, c] = new_out[r, c-1]
                        changed = True
                    # Check up-down
                    elif r > 0 and r < H-1 and new_out[r-1, c] != 0 and new_out[r-1, c] == new_out[r+1, c]:
                        new_out[r, c] = new_out[r-1, c]
                        changed = True
        out = new_out

    # Intersection resolution
    # At each cell, check if it's at an intersection of two different-colored arms
    # If so, swap to the color NOT in the original input
    new_out = out.copy()
    for r in range(H):
        for c in range(W):
            if out[r, c] == 0:
                continue
            current = int(out[r, c])

            # Check if there's a perpendicular arm of a different color
            # Horizontal arm check: same color to left and right
            h_arm = False
            if c > 0 and c < W-1 and out[r, c-1] == current and out[r, c+1] == current:
                h_arm = True

            # Vertical arm of different color check
            v_arm_color = 0
            if r > 0 and r < H-1:
                above = int(out[r-1, c])
                below = int(out[r+1, c])
                if above != 0 and above != current and above == below:
                    v_arm_color = above
                elif above != 0 and above != current:
                    # check further
                    pass
                elif below != 0 and below != current:
                    pass

            # If this cell is on a horizontal arm AND there's a vertical arm of different color
            if h_arm and v_arm_color != 0:
                # This is an intersection - swap
                if orig[r, c] == current:
                    new_out[r, c] = v_arm_color
                elif orig[r, c] == v_arm_color:
                    new_out[r, c] = current  # keep

            # Similarly check vertical arm with horizontal crossing
            v_arm = False
            if r > 0 and r < H-1 and out[r-1, c] == current and out[r+1, c] == current:
                v_arm = True

            h_arm_color = 0
            if c > 0 and c < W-1:
                left = int(out[r, c-1])
                right = int(out[r, c+1])
                if left != 0 and left != current and left == right:
                    h_arm_color = left

            if v_arm and h_arm_color != 0:
                if orig[r, c] == current:
                    new_out[r, c] = h_arm_color
                elif orig[r, c] == h_arm_color:
                    new_out[r, c] = current

    out = new_out
    return out.tolist()

# Test
for i, s in enumerate(train_samples):
    result = solve(s['input'])
    expected = s['output']
    correct = sum(1 for r in range(len(expected)) for c in range(len(expected[0])) if result[r][c] == expected[r][c])
    total = len(expected) * len(expected[0])
    print(f"Example {i}: {correct}/{total} correct")
    if correct < total:
        diffs = [(r,c,result[r][c],expected[r][c]) for r in range(len(expected)) for c in range(len(expected[0])) if result[r][c] != expected[r][c]]
        for r,c,got,exp in diffs[:10]:
            print(f"  ({r},{c}): got {got}, expected {exp}")
        if len(diffs) > 10:
            print(f"  ... and {len(diffs)-10} more differences")

