                markers_2.append((r, c))
            elif inp[r, c] == 4:
                markers_4.append((r, c))

    # Step 2: For each marker, determine its line color
    # The line color is the most common adjacent non-zero, non-marker color
    def get_line_color(r, c):
        colors = []
        for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
            nr, nc = r+dr, c+dc
            if 0 <= nr < H and 0 <= nc < W and inp[nr, nc] not in [0, 2, 4]:
                colors.append(int(inp[nr, nc]))
        if colors:
            return max(set(colors), key=colors.count)
        return 0

