    for r, c in markers_4:
        line_color = get_line_color(r, c)
        # Find adjacent cell with line_color (the arm endpoint)
        for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
            nr, nc = r+dr, c+dc
            if 0 <= nr < H and 0 <= nc < W and inp[nr, nc] == line_color:
                # This is the arm endpoint
                # Flip direction: from (nr,nc) toward (r,c)
                flip_dr, flip_dc = r-nr, c-nc

                # Remove old arm (opposite direction from arm endpoint)
                old_dr, old_dc = -flip_dr, -flip_dc
                cr, cc = nr + old_dr, nc + old_dc
                while 0 <= cr < H and 0 <= cc < W:
