                        out[cr, cc] = 0
                    cr += old_dr
                    cc += old_dc

                # Create new arm (from marker position in flip direction)
                out[r, c] = line_color  # marker becomes line color
                cr, cc = r + flip_dr, c + flip_dc
                while 0 <= cr < H and 0 <= cc < W:
                    out[cr, cc] = line_color
                    cr += flip_dr
                    cc += flip_dc
                break

