# 
# 1. Process markers to determine path shapes
# 2. Track which cells are "marker-defined" (on marker arms)
# 3. At intersections on marker-defined arms: swap
# 4. At intersections NOT on marker-defined arms: keep
# 5. Fill gaps
# 
# The tricky part is defining "marker-defined arm cells":
# For marker 2: cells on the same row/column as the marker, between the marker 
#   and either another marker or the end of existing same-color cells
# For marker 4 old arm: cells from the corner going in the old direction
# For marker 4 new arm: NOT marker-defined (don't swap)

def solve(grid):
    grid = [row[:] for row in grid]
    H = len(grid)
    W = len(grid[0])
    inp = np.array(grid)
    out = inp.copy()

    markers_2 = []
    markers_4 = []
    for r in range(H):
        for c in range(W):
            if inp[r, c] == 2:
                markers_2.append((r, c))
            elif inp[r, c] == 4:
                markers_4.append((r, c))

    def get_line_color(r, c):
        colors = []
        for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
            nr, nc = r+dr, c+dc
            if 0 <= nr < H and 0 <= nc < W and inp[nr, nc] not in [0, 2, 4]:
                colors.append(int(inp[nr, nc]))
        if colors:
            return max(set(colors), key=colors.count)
        return 0

    # Track marker-defined arm cells
    marker_arm_cells = set()

    # Process marker 4 (flip)
    for r, c in markers_4:
        line_color = get_line_color(r, c)
        for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
            nr, nc = r+dr, c+dc
            if 0 <= nr < H and 0 <= nc < W and inp[nr, nc] == line_color:
                flip_dr, flip_dc = r-nr, c-nc
                old_dr, old_dc = -flip_dr, -flip_dc

                # Mark and remove old arm
                cr, cc = nr + old_dr, nc + old_dc
                while 0 <= cr < H and 0 <= cc < W:
                    if out[cr, cc] == line_color:
                        marker_arm_cells.add((cr, cc))
                        out[cr, cc] = 0
                    cr += old_dr
                    cc += old_dc

                # Also mark the corner cell and adjacent cells on old direction
                marker_arm_cells.add((nr, nc))  # the corner

                # Create new arm (NOT marker_arm_cells - these are "definitive")
                out[r, c] = line_color
                cr, cc = r + flip_dr, c + flip_dc
                while 0 <= cr < H and 0 <= cc < W:
                    out[cr, cc] = line_color
                    cr += flip_dr
                    cc += flip_dc
                break

    # Process marker 2 (replace) and track arms
    for r, c in markers_2:
        line_color = get_line_color(r, c)
        out[r, c] = line_color
        marker_arm_cells.add((r, c))

    # Fill between marker 2 pairs and track
    marker_by_color = defaultdict(list)
    for r, c in markers_2:
        marker_by_color[get_line_color(r,c)].append((r,c))
    for lc, positions in marker_by_color.items():
        for i in range(len(positions)):
            for j in range(i+1, len(positions)):
                r1,c1 = positions[i]
                r2,c2 = positions[j]
                if r1 == r2:
                    for cc in range(min(c1,c2), max(c1,c2)+1):
                        marker_arm_cells.add((r1, cc))
                        if out[r1,cc] == 0:
                            out[r1,cc] = lc
                elif c1 == c2:
                    for rr in range(min(r1,r2), max(r1,r2)+1):
                        marker_arm_cells.add((rr, c1))
                        if out[rr,c1] == 0:
                            out[rr,c1] = lc

    # For single markers: mark the arm extending from the marker along the row/col
    for lc, positions in marker_by_color.items():
        for r, c in positions:
            # Check if this marker has a partner on the same row
            has_row_partner = any(r2 == r and c2 != c for r2, c2 in positions)
            has_col_partner = any(c2 == c and r2 != r for r2, c2 in positions)

            # If no row partner, mark the entire row arm extending from marker
            if not has_row_partner:
                # Mark left
                for cc in range(c-1, -1, -1):
                    if out[r, cc] == lc or (inp[r, cc] == lc):
                        marker_arm_cells.add((r, cc))
                    elif out[r, cc] == 0 and cc > 0 and (inp[r, cc-1] == lc or out[r, cc-1] == lc):
                        marker_arm_cells.add((r, cc))  # gap cell
                    else:
