                # Mark right
                for cc in range(c+1, W):
                    if out[r, cc] == lc or (inp[r, cc] == lc):
                        marker_arm_cells.add((r, cc))
                    elif out[r, cc] == 0 and cc < W-1 and (inp[r, cc+1] == lc or out[r, cc+1] == lc):
