                    if out[rr, c] == lc or (inp[rr, c] == lc):
                        marker_arm_cells.add((rr, c))
                    elif out[rr, c] == 0 and rr < H-1 and (inp[rr+1, c] == lc or out[rr+1, c] == lc):
                        marker_arm_cells.add((rr, c))
                    else:
                        break

    # Swap intersections on marker arms
    swaps = {}
    for r in range(H):
        for c in range(W):
            if (r, c) not in marker_arm_cells:
                continue
            cell = int(out[r, c])
            if cell == 0:
                continue

            v_col = None
            h_col = None
            if r > 0 and r < H-1:
                above = int(out[r-1, c])
                below = int(out[r+1, c])
                if above != 0 and above == below:
                    v_col = above
            if c > 0 and c < W-1:
                left = int(out[r, c-1])
                right = int(out[r, c+1])
                if left != 0 and left == right:
                    h_col = left

            if v_col is not None and h_col is not None and v_col != h_col:
                if cell == v_col:
                    swaps[(r, c)] = h_col
                elif cell == h_col:
                    swaps[(r, c)] = v_col

    for (r, c), new_color in swaps.items():
        out[r, c] = new_color

    # Fill 1-cell gaps
    changed = True
    while changed:
        changed = False
        for r in range(H):
            for c in range(W):
                if out[r, c] != 0:
                    continue
                v_fill = None
                h_fill = None
                if r > 0 and r < H-1:
                    above = int(out[r-1, c])
                    below = int(out[r+1, c])
                    if above != 0 and above == below:
                        v_fill = above
                if c > 0 and c < W-1:
                    left = int(out[r, c-1])
                    right = int(out[r, c+1])
                    if left != 0 and left == right:
                        h_fill = left

                if v_fill is not None and h_fill is not None:
                    # Conflict: choose based on marker arm membership
                    if (r, c) in marker_arm_cells:
                        # Fill with the OTHER color (swap)
                        # Actually, this is a marker arm cell with 0 value
                        # The marker arm color is one of v_fill/h_fill
                        # Fill with the other
                        # Need to know which is the marker arm color
                        # For now, just pick the one that's NOT on the marker arm direction
                        pass  # Handle below
                    else:
                        # Not on marker arm, skip for now
                        continue

                if v_fill is not None and h_fill is None:
                    out[r, c] = v_fill
                    changed = True
                elif h_fill is not None and v_fill is None:
                    out[r, c] = h_fill
                    changed = True

    return out.tolist()

for i, s in enumerate(train_samples):
    result = np.array(solve(s['input']))
    expected = np.array(s['output'])
